<?phpnamespace app\dep\Article;use app\enum\ArticleEnum;use app\model\Article\ArticleModel;use app\enum\CommonEnum;use support\Db;class ArticleDep{    public $model;    public function __construct()    {        $this->model = new ArticleModel();    }    public function first($id)    {        $res = $this->model->where('id', $id)->first();        return $res;    }     public function firstByTitle($name)    {        $res = $this->model->where('title', $name)->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function carousel()    {        $res = $this->model->where("status",ArticleEnum::RELEASE)->where('is_carousel', CommonEnum::YES)->where('is_del', CommonEnum::NO)->get();        return $res;    }    public function all()    {        $res = $this->model->all();        return $res;    }    public function allOK()    {        $res = $this->model->where('is_del', CommonEnum::NO)->get();        return $res;    }    public function releaseAll()    {        $res = $this->model->select(['tag_id','category_id'])->where('is_del', CommonEnum::NO)->where('status', ArticleEnum::RELEASE)->get();        return $res;    }//    public function census() {//        // 注意：这里将 CommonEnum::NO 假设为一个常量，自己确保它已经定义//        $res = Db::table('article')//            ->selectRaw('COUNT(id) AS num, status')//            ->where('is_del', CommonEnum::NO)//            ->groupBy('status')//            ->get();////        return $res;//    }    public function census() {        $res = $this->model            ->selectRaw('COUNT(id) AS num, status')            ->where('is_del', CommonEnum::NO)            ->groupBy('status')            ->get();        return $res;    }    public function add($data)    {        $res = $this->model->insertGetId($data);        return $res;    }    public function edit($id, $data)    {        if(!is_array($id)){            $id = [$id];        }        $res = $this->model->whereIn('id', $id)->update($data);        return $res;    }    public function batchEdit($ids, $data)    {        $res = $this->model->whereIn('id', $ids)->update($data);        return $res;    }    public function del($id, $data)    {        if(!is_array($id)){            $id = [$id];        }        $res = $this->model->whereIn('id', $id)->update($data);        return $res;    }    public function list($param){        $res = $this->model            ->where('is_del', CommonEnum::NO)            ->when(!empty($param['title']), function ($query) use ($param) {                $query->where('title','like' ,"%{$param['title']}%");            })            ->when(!empty($param['type']), function ($query) use ($param) {                $query->where('type',$param['type']);            })            ->when(!empty($param['category_id']), function ($query) use ($param) {                $query->where('category_id',$param['category_id']);            })            ->when(!empty($param['status']), function ($query) use ($param) {                $query->where('status',$param['status']);            })            ->when(!empty($param['tag_id']), function ($query) use ($param) {                $tagIds = $param['tag_id'];                // 使用 JSON 查询筛选                $query->where(function ($query) use ($tagIds) {                    foreach ($tagIds as $tagId) {                        $query->orWhereRaw("JSON_CONTAINS(tag_id, ?)", [json_encode($tagId)]);                    }                });            })            ->when(!empty($param['sortField']) && !empty($param['sortOrder']), function ($query) use ($param) {                // 根据传入的排序字段和顺序进行排序                $sortOrder = strtolower($param['sortOrder']) === 'asc' ? 'asc' : 'desc';                $query->orderBy($param['sortField'], $sortOrder);            })            ->orderBy('is_top','desc')            ->paginate($param['page_size'], ['*'], 'page', $param['current_page']);        return $res;    }}